import threading
from typing import Dict

class StockManager:
    def __init__(self):
        self.items: Dict[str, int] = {}
        self._lock = threading.Lock()

    def add_stock(self, item_id: str, quantity: int):
        with self._lock:
            self.items[item_id] = self.items.get(item_id, 0) + quantity

    def check_available(self, item_id: str, quantity: int) -> bool:
        with self._lock:
            return self.items.get(item_id, 0) >= quantity

    def reserve(self, item_id: str, quantity: int) -> bool:
        with self._lock:
            if self.items.get(item_id, 0) >= quantity:
                self.items[item_id] -= quantity
                return True
            return False
